class ChessPositionEvaluator:
    def __init__(self, position):
        self.position = position
        self.board = self.parse_position(position)
        self.piece_values = {'P': 1, 'N': 3, 'B': 3, 'R': 5, 'Q': 9, 'K': 100}

    def parse_position(self, position):
        # assuming position is in FEN format
        rows = position.split('/')
        board = []
        for row in rows:
            row_pieces = []
            for char in row:
                if char.isdigit():
                    row_pieces.extend(['.' for _ in range(int(char))])
                else:
                    row_pieces.append(char)
            board.append(row_pieces)
        return board

    def evaluate_position(self):
        white_score = 0
        black_score = 0
        for i in range(8):
            for j in range(8):
                piece = self.board[i][j]
                if piece.isupper():
                    white_score += self.piece_values.get(piece, 0)
                elif piece.islower():
                    black_score += self.piece_values.get(piece.upper(), 0)

        controlled_squares = self.count_controlled_squares()
        active_moves = self.count_active_moves()
        check_possibilities = self.count_check_possibilities()
        mate_possibilities = self.count_mate_possibilities()

        evaluation = {
            'material_advantage': white_score - black_score,
            'controlled_squares': controlled_squares,
            'active_moves': active_moves,
            'check_possibilities': check_possibilities,
            'mate_possibilities': mate_possibilities
        }

        if evaluation['material_advantage'] > 0:
            print("White has an advantage")
        elif evaluation['material_advantage'] < 0:
            print("Black has an advantage")
        else:
            print("The position is equal")

        print("Material advantage:", evaluation['material_advantage'])
        print("Controlled squares:", evaluation['controlled_squares'])
        print("Active moves:", evaluation['active_moves'])
        print("Check possibilities:", evaluation['check_possibilities'])
        print("Mate possibilities:", evaluation['mate_possibilities'])

    def count_controlled_squares(self):
        controlled_squares = 0
        for i in range(8):
            for j in range(8):
                piece = self.board[i][j]
                if piece.isupper():
                    controlled_squares += self.count_controlled_squares_by_piece(piece, i, j)
                elif piece.islower():
                    controlled_squares -= self.count_controlled_squares_by_piece(piece.upper(), i, j)
        return controlled_squares

    def count_controlled_squares_by_piece(self, piece, i, j):
