class Board:
    def __init__(self):
        self.pieces = []
        self.controlled_squares = {'white': 0, 'black': 0}
        self.active_moves = {'white': 0, 'black': 0}
        self.check = False
        self.mate = False

    def add_piece(self, piece):
        self.pieces.append(piece)

    def evaluate_position(self):
        material_advantage = self.calculate_material_advantage()
        mobility_advantage = self.calculate_mobility_advantage()
        control_advantage = self.calculate_control_advantage()
        check_advantage = self.calculate_check_advantage()
        mate_advantage = self.calculate_mate_advantage()

        evaluation = material_advantage + mobility_advantage + control_advantage + check_advantage + mate_advantage
        return evaluation

    def calculate_material_advantage(self):
        material_value = {'pawn': 1, 'knight': 3, 'bishop': 3, 'rook': 5, 'queen': 9}
        white_value = 0
        black_value = 0
        for piece in self.pieces:
            if piece.color == 'white':
                white_value += material_value[piece.type]
            else:
                black_value += material_value[piece.type]
        return white_value - black_value

    def calculate_mobility_advantage(self):
        mobility_value = {'pawn': 2, 'knight': 4, 'bishop': 6, 'rook': 8, 'queen': 10}
        white_value = 0
        black_value = 0
        for piece in self.pieces:
            if piece.color == 'white':
                white_value += mobility_value[piece.type]
            else:
                black_value += mobility_value[piece.type]
        return white_value - black_value

    def calculate_control_advantage(self):
        control_value = {'pawn': 1, 'knight': 2, 'bishop': 3, 'rook': 4, 'queen': 5}
        white_value = 0
        black_value = 0
        for piece in self.pieces:
            if piece.color == 'white':
                white_value += control_value[piece.type]
            else:
                black_value += control_value[piece.type]
        return white_value - black_value

    def calculate_check_advantage(self):
        if self.check:
            return 10 if self.controlled_squares['black'] > self.controlled_squares['white'] else -10
        return 0

    def calculate_mate_advantage(self):
        if self.mate:
            return 100 if self.controlled_squares['black'] > self.controlled_squares['white'] else -100
        return 0

def create_board(position):
    board = Board()
    rows = position.split('/')
    for y, row in enumerate(rows):
        x = 0
        for char in row:
            if char.isdigit():
                x += int(char)
            else:
                piece_type = None
                if char.lower() == 'p':
                    piece_type = 'pawn'
                elif char.lower() == 'n':
                    piece_type = 'knight'
                elif char.lower() == 'b':
                    piece_type = 'bishop'
                elif char.lower() == 'r':
                    piece_type = 'rook'
                elif char.lower() == 'q':
                    piece_type = 'queen'
                piece_color = 'white' if char.isupper() else 'black'
                piece = Piece(piece_type, piece_color, x, y)
                board.add_piece(piece)
                x += 1
    return board

