class ChessPositionEvaluator:
    def __init__(self, position):
        self.position = position
        self.board = self.parse_position(position)
        self.piece_values = {'P': 1, 'N': 3, 'B': 3, 'R': 5, 'Q': 9, 'K': 100}
        self.controlled_squares = {'white': 0, 'black': 0}
        self.active_moves = {'white': 0, 'black': 0}
        self.check_possibilities = {'white': 0, 'black': 0}
        self.mate_possibilities = {'white': 0, 'black': 0}

    def parse_position(self, position):
        # assuming position is in FEN format
        board = []
        rows = position.split('/')
        for row in rows:
            row_pieces = []
            for char in row:
                if char.isdigit():
                    row_pieces.extend(['.' for _ in range(int(char))])
                else:
                    row_pieces.append(char)
            board.append(row_pieces)
        return board

    def evaluate_position(self):
        material_balance = 0
        for row in self.board:
            for piece in row:
                if piece.isupper():
                    material_balance += self.piece_values.get(piece, 0)
                elif piece.islower():
                    material_balance -= self.piece_values.get(piece.upper(), 0)

        for row in range(8):
            for col in range(8):
                piece = self.board[row][col]
                if piece.isupper():
                    self.controlled_squares['white'] += self.count_controlled_squares(row, col, 'white')
                    self.active_moves['white'] += self.count_active_moves(row, col, 'white')
                    self.check_possibilities['white'] += self.count_check_possibilities(row, col, 'white')
                    self.mate_possibilities['white'] += self.count_mate_possibilities(row, col, 'white')
                elif piece.islower():
                    self.controlled_squares['black'] += self.count_controlled_squares(row, col, 'black')
                    self.active_moves['black'] += self.count_active_moves(row, col, 'black')
                    self.check_possibilities['black'] += self.count_check_possibilities(row, col, 'black')
                    self.mate_possibilities['black'] += self.count_mate_possibilities(row, col, 'black')

        evaluation = {
            'material_balance': material_balance,
            'controlled_squares': self.controlled_squares,
            'active_moves': self.active_moves,
            'check_possibilities': self.check_possibilities,
            'mate_possibilities': self.mate_possibilities
        }
        return evaluation

    def count_controlled_squares(self, row, col, color):
        # assuming a simple count of adjacent squares
        count = 0
        for dr in [-1, 0, 1]:
            for dc in [-1, 0, 1]:
                if dr == 0 and dc == 0:
                    continue
                nr, nc = row + dr, col + dc
                if 0 <= nr < 8 and 0 <= nc < 8:
                    piece = self.board[nr][nc]
                    if piece == '.':
                        count += 1
        return count

    def count_active_moves(self, row, col, color):
        # assuming a simple count of possible moves
        count = 0
        piece = self.board[row][col]
        if piece.upper() == 'P':
            # pawn moves
            if color == 'white' and row > 0 and self.board[row-1][col] == '.':
                count += 1
            if color == 'black' and row < 7 and self.board[row+1][col] == '.':
                count += 1
        elif piece.upper() == 'N':
            # knight moves
            for dr in [-2, -1, 1, 2]:
                for dc in [-2, -1, 1, 2]:
                    if abs(dr) + abs(dc) == 3:
                        nr, nc = row + dr, col + dc
                        if 0 <= nr < 8 and 0 <= nc < 8:
                            piece = self.board[nr][nc]
                            if piece == '.' or piece.islower() != (color == 'white'):
                                count += 1
        elif piece.upper() == 'B':
            # bishop moves
            for dr in [-1, 1]:
                for dc in [-1, 1]:
                    nr, nc = row + dr, col + dc
                    while 0 <= nr < 8 and 0 <= nc < 8:
                        piece = self.board[nr][nc]
                        if piece == '.':
                            count += 1
                            nr += dr
                            nc += dc
                        elif piece.islower() != (color == 'white'):
                            count += 1
                            break
                        else:
                            break
        elif piece.upper() == 'R':
            # rook moves
            for dr, dc in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
                nr, nc = row + dr, col + dc
                while 0 <= nr < 8 and 0 <= nc < 8:
                    piece = self.board[nr][nc]
                    if piece == '.':
                        count += 1
                        nr += dr
                        nc += dc
                    elif piece.islower() != (color == 'white'):
                        count += 1
                        break
                    else:
                        break
        elif piece.upper() == 'Q':
            # queen moves
            for dr in [-1, 0, 1]:
                for dc in [-1, 0, 1]:
                    if dr == 0 and dc == 0:
                        continue
                    nr, nc = row + dr, col + dc
                    while 0 <= nr < 8 and 0 <= nc < 8:
                        piece = self.board[nr][nc]
                        if piece == '.':
                            count += 1
                            nr += dr
                            nc += dc
                        elif piece.islower() != (color == 'white'):
                            count += 1
                            break
                        else:
                            break
        return count

    def count_check_possibilities(self, row, col, color):
        # assuming a simple count of possible checks
        count = 0
        piece = self.board[row][col]
        if piece.upper() == 'P':
            # pawn checks
            if color == 'white' and row > 0 and col > 0 and self.board[row-1][col-1].islower():
