import chess

def evaluate_position(board):
    # Initialize evaluation metrics
    white_advantage = 0
    black_advantage = 0
    controlled_squares_white = 0
    controlled_squares_black = 0
    active_moves_white = 0
    active_moves_black = 0
    check_possibilities_white = 0
    check_possibilities_black = 0
    mate_possibilities_white = 0
    mate_possibilities_black = 0

    # Evaluate piece values
    for piece in board.piece_map().values():
        if piece.color == chess.WHITE:
            if piece.piece_type == chess.PAWN:
                white_advantage += 1
            elif piece.piece_type == chess.KNIGHT or piece.piece_type == chess.BISHOP:
                white_advantage += 3
            elif piece.piece_type == chess.ROOK:
                white_advantage += 5
            elif piece.piece_type == chess.QUEEN:
                white_advantage += 9
        elif piece.color == chess.BLACK:
            if piece.piece_type == chess.PAWN:
                black_advantage += 1
            elif piece.piece_type == chess.KNIGHT or piece.piece_type == chess.BISHOP:
                black_advantage += 3
            elif piece.piece_type == chess.ROOK:
                black_advantage += 5
            elif piece.piece_type == chess.QUEEN:
                black_advantage += 9

    # Evaluate controlled squares
    for square in chess.SQUARES:
        if board.is_attacked_by(chess.WHITE, square):
            controlled_squares_white += 1
        elif board.is_attacked_by(chess.BLACK, square):
            controlled_squares_black += 1

    # Evaluate active moves
    for move in board.legal_moves:
        if move.from_square in board.piece_map() and board.piece_at(move.from_square).color == chess.WHITE:
            active_moves_white += 1
        elif move.from_square in board.piece_map() and board.piece_at(move.from_square).color == chess.BLACK:
            active_moves_black += 1

    # Evaluate check and mate possibilities
    if board.is_check():
        if board.turn == chess.WHITE:
            check_possibilities_black += 1
        else:
            check_possibilities_white += 1
    if board.is_checkmate():
        if board.turn == chess.WHITE:
            mate_possibilities_black += 1
        else:
            mate_possibilities_white += 1

    # Calculate overall evaluation
    evaluation = white_advantage - black_advantage + controlled_squares_white - controlled_squares_black + active_moves_white - active_moves_black + check_possibilities_white - check_possibilities_black + mate_possibilities_white - mate_possibilities_black

    return evaluation

