class ChessPositionEvaluator:
    def __init__(self, board):
        self.board = board
        self.piece_values = {'P': 1, 'N': 3, 'B': 3, 'R': 5, 'Q': 9}
        self.controlled_squares = {'white': 0, 'black': 0}
        self.active_moves = {'white': 0, 'black': 0}
        self.checks = {'white': 0, 'black': 0}
        self.mates = {'white': 0, 'black': 0}

    def evaluate_position(self):
        self.evaluate_material()
        self.evaluate_controlled_squares()
        self.evaluate_active_moves()
        self.evaluate_checks_and_mates()
        return self.get_evaluation()

    def evaluate_material(self):
        material = {'white': 0, 'black': 0}
        for row in self.board:
            for piece in row:
                if piece.isupper():
                    material['white'] += self.piece_values.get(piece, 0)
                elif piece.islower():
                    material['black'] += self.piece_values.get(piece.upper(), 0)
        self.material = material

