                if i < 7 and j < 7 and self.board[i+1][j+1] == '':
                    controlled += 1
        elif piece == 'N':
            for x, y in [(-2, -1), (-2, 1), (-1, -2), (-1, 2), (1, -2), (1, 2), (2, -1), (2, 1)]:
                if 0 <= i+x < 8 and 0 <= j+y < 8 and self.board[i+x][j+y] == '':
                    controlled += 1
        elif piece == 'B':
            for x, y in [(-1, -1), (-1, 1), (1, -1), (1, 1)]:
