import re

def evaluate_position(position):
    # Parse position
    position = position.replace(" ", "")
    position = position.replace("\n", "")
    position = re.sub(r"[0-9]", "", position)
    position = position.upper()

    # Initialize piece values
    piece_values = {
        'R': 5,
        'N': 3,
        'B': 3,
        'Q': 9,
        'K': 1,
        'P': 1
    }

    # Initialize material balance
    material_balance = 0

    # Initialize control of center squares
    center_squares = ['D4', 'D5', 'E4', 'E5']
    center_control = {'WHITE': 0, 'BLACK': 0}

    # Initialize active moves
    active_moves = {'WHITE': 0, 'BLACK': 0}

    # Initialize check and mate possibilities
    check_possibilities = {'WHITE': 0, 'BLACK': 0}
    mate_possibilities = {'WHITE': 0, 'BLACK': 0}

    # Evaluate position
    for i in range(8):
        for j in range(8):
            square = chr(65 + j) + str(8 - i)
            piece = position[i * 8 + j]

            if piece!= '.':
                if piece.isupper():
                    material_balance += piece_values[piece]
                    if square in center_squares:
                        center_control['WHITE'] += 1
                    active_moves['WHITE'] += 1
                else:
                    material_balance -= piece_values[piece.upper()]
                    if square in center_squares:
                        center_control['BLACK'] += 1
                    active_moves['BLACK'] += 1

    # Evaluate check and mate possibilities
    # This is a simplified evaluation and does not take into account many factors
    if material_balance > 0:
        check_possibilities['WHITE'] += 1
        mate_possibilities['WHITE'] += 1
    elif material_balance < 0:
        check_possibilities['BLACK'] += 1
        mate_possibilities['BLACK'] += 1

    # Calculate final evaluation
    evaluation = material_balance + (center_control['WHITE'] - center_control['BLACK']) + (active_moves['WHITE'] - active_moves['BLACK']) + (check_possibilities['WHITE'] - check_possibilities['BLACK']) + (mate_possibilities['WHITE'] - mate_possibilities['BLACK'])

    return evaluation

