        self.calculate_material_balance()
        self.evaluate_control_of_center()
        self.evaluate_active_moves()
        self.evaluate_pawn_structure()
        self.evaluate_king_safety()
        return self.material_balance

    def calculate_material_balance(self):
        for row in self.board:
            for piece in row:
                if piece.isupper():
                    self.material_balance += self.piece_values.get(piece, 0)
                elif piece.islower():
                    self.material_balance -= self.piece_values.get(piece.upper(), 0)

    def evaluate_control_of_center(self):
        center_control = 0
        for i in range(4, 5):
            for j in range(4, 5):
                if self.board[i][j].isupper():
                    center_control += 1
                elif self.board[i][j].islower():
                    center_control -= 1
        self.material_balance += center_control * 0.1

