import chess

def evaluate_position(board):
    # Initialize evaluation score
    score = 0

    # Material evaluation
    for piece in board.piece_map().values():
        if piece.color == chess.WHITE:
            if piece.piece_type == chess.PAWN:
                score += 1
            elif piece.piece_type == chess.KNIGHT or piece.piece_type == chess.BISHOP:
                score += 3
            elif piece.piece_type == chess.ROOK:
                score += 5
            elif piece.piece_type == chess.QUEEN:
                score += 9
        else:
            if piece.piece_type == chess.PAWN:
                score -= 1
            elif piece.piece_type == chess.KNIGHT or piece.piece_type == chess.BISHOP:
                score -= 3
            elif piece.piece_type == chess.ROOK:
                score -= 5
            elif piece.piece_type == chess.QUEEN:
                score -= 9

    # Controlled squares evaluation
    controlled_squares = 0
    for square in chess.SQUARES:
        if board.is_attacked_by(chess.WHITE, square):
            controlled_squares += 1
        elif board.is_attacked_by(chess.BLACK, square):
            controlled_squares -= 1
    score += controlled_squares / 100

    # Mobility evaluation
    mobility = 0
    for piece in board.piece_map().values():
        if piece.color == chess.WHITE:
            mobility += len(list(board.legal_moves))
        else:
            mobility -= len(list(board.legal_moves))
    score += mobility / 1000

    # Pawn structure evaluation
    pawn_structure = 0
    for square in chess.SQUARES:
        if board.piece_at(square) == chess.PAWN:
            if board.color_at(square) == chess.WHITE:
                pawn_structure += 1
            else:
                pawn_structure -= 1
    score += pawn_structure / 100

    # King safety evaluation
    king_safety = 0
    for square in chess.SQUARES:
        if board.piece_at(square) == chess.KING:
            if board.color_at(square) == chess.WHITE:
                king_safety += 1
