    for piece in board.piece_map().values():
        if piece.color == chess.WHITE:
            if piece.piece_type == chess.PAWN:
                score += 1
            elif piece.piece_type == chess.KNIGHT or piece.piece_type == chess.BISHOP:
                score += 3
            elif piece.piece_type == chess.ROOK:
                score += 5
            elif piece.piece_type == chess.QUEEN:
                score += 9
        else:
            if piece.piece_type == chess.PAWN:
                score -= 1
            elif piece.piece_type == chess.KNIGHT or piece.piece_type == chess.BISHOP:
                score -= 3
            elif piece.piece_type == chess.ROOK:
                score -= 5
            elif piece.piece_type == chess.QUEEN:
                score -= 9

    # Controlled squares evaluation
    for square in chess.SQUARES:
        if board.is_attacked_by(chess.WHITE, square):
            score += 0.1
        elif board.is_attacked_by(chess.BLACK, square):
            score -= 0.1

    # Mobility evaluation
    white_mobility = 0
    black_mobility = 0
    for piece in board.piece_map().values():
        if piece.color == chess.WHITE:
            white_mobility += len(list(board.legal_moves))
        else:
            black_mobility += len(list(board.legal_moves))
    score += (white_mobility - black_mobility) / 100

    # Pawn structure evaluation
    white_pawns = [piece for piece in board.piece_map().values() if piece.color == chess.WHITE and piece.piece_type == chess.PAWN]
    black_pawns = [piece for piece in board.piece_map().values() if piece.color == chess.BLACK and piece.piece_type == chess.PAWN]
    score += len(white_pawns) * 0.1 - len(black_pawns) * 0.1

