                    piece_type = piece[1]
                    evaluation += self.color_values[color] * self.piece_values[piece_type]
        return evaluation

    def count_controlled_squares(self, color):
        controlled_squares = 0
        for row in range(8):
            for col in range(8):
                if self.is_controlled(row, col, color):
                    controlled_squares += 1
        return controlled_squares

    def is_controlled(self, row, col, color):
        for r in range(8):
            for c in range(8):
                piece = self.board[r][c]
                if piece != '.' and piece[0] == color:
                    if self.can_move(r, c, row, col):
                        return True
        return False

    def can_move(self, start_row, start_col, end_row, end_col):
        piece = self.board[start_row][start_col]
        piece_type = piece[1]
        if piece_type == 'p':
            return self.can_pawn_move(start_row, start_col, end_row, end_col)
        elif piece_type == 'n':
            return self.can_knight_move(start_row, start_col, end_row, end_col)
        elif piece_type == 'b':
            return self.can_bishop_move(start_row, start_col, end_row, end_col)
        elif piece_type == 'r':
            return self.can_rook_move(start_row, start_col, end_row, end_col)
        elif piece_type == 'q':
            return self.can_queen_move(start_row, start_col, end_row, end_col)

    def can_pawn_move(self, start_row, start_col, end_row, end_col):
        if start_col == end_col:
            if self.board[end_row][end_col] == '.':
                if start_row == 1 and end_row == 3:
                    return True
                elif start_row == 6 and end_row == 4:
                    return True
                elif abs(start_row - end_row) == 1:
                    return True
        elif abs(start_col - end_col) == 1:
            if self.board[end_row][end_col] != '.' and self.board[end_row][end_col][0] != self.board[start_row][start_col][0]:
                return True
        return False

    def can_knight_move(self, start_row, start_col, end_row, end_col):
        if abs(start_row - end_row) == 2 and abs(start_col - end_col) == 1:
            return True
        elif abs(start_row - end_row) == 1 and abs(start_col - end_col) == 2:
            return True
        return False

    def can_bishop_move(self, start_row, start_col, end_row, end_col):
        if abs(start_row - end_row) == abs(start_col - end_col):
            row_dir = 1 if end_row > start_row else -1
            col_dir = 1 if end_col > start_col else -1
            for i in range(1, abs(start_row - end_row)):
                if self.board[start_row + i * row_dir][start_col + i * col_dir] != '.':
                    return False
            return True
        return False

    def can_rook_move(self, start_row, start_col, end_row, end_col):
        if start_row == end_row:
            col_dir = 1 if end_col > start_col else -1
            for i in range(1, abs(start_col - end_col)):
                if self.board[start_row][start_col + i * col_dir] != '.':
                    return False
            return True
        elif start_col == end_col:
            row_dir = 1 if end_row > start_row else -1
            for i in range(1, abs(start_row - end_row)):
                if self.board[start_row + i * row_dir][start_col] != '.':
                    return False
            return True
        return False

    def can_queen_move(self, start_row, start_col, end_row, end_col):
        return self.can_bishop_move(start_row, start_col, end_row, end_col) or self.can_rook_move(start_row, start_col, end_row, end_col)

    def evaluate_mobility(self, color):
        mobility = 0
        for row in range(8):
            for col in range(8):
                piece = self.board[row][col]
                if piece != '.' and piece[0] == color:
                    for r in range(8):
                        for c in range(8):
                            if self.can_move(row, col, r, c):
                                mobility += 1
        return mobility

    def evaluate_pawn_structure(self, color):
        pawns = []
        for row in range(8):
            for col in range(8):
                piece = self.board[row][col]
                if piece != '.' and piece[1] == 'p' and piece[0] == color:
                    pawns.append((row, col))
        structure = 0
        for pawn in pawns:
            for other_pawn in pawns:
                if pawn != other_pawn and abs(pawn[1] - other_pawn[1]) == 1:
                    structure += 1
        return structure

    def evaluate_king_safety(self, color):
        king_row, king_col = None, None
        for row in range(8):
            for col in range(8):
                piece = self.board[row][col]
                if piece != '.' and piece[1] == 'k' and piece[0] == color:
                    king_row, king_col = row, col
        safety = 0
        for row in range(max(0, king_row - 1), min(8, king_row + 2)):
            for col in range(max(0, king_col - 1), min(8, king_col + 2)):
                piece = self.board[row][col]
                if piece != '.' and piece[0] != color:
                    safety -= 1
        return safety

